#!/usr/bin/env python3\n\nimport json\nimport datetime\n\nclass HabitTracker:\n    def __init__(self, data_file='habits.json'):\n        self.data_file = data_file\n        self.habits = self.load_habits()\n\n    def load_habits(self):\n        try:\n            with open(self.data_file, 'r') as f:\n                return json.load(f)\n        except FileNotFoundError:\n            return {}\n\n    def save_habits(self):\n        with open(self.data_file, 'w') as f:\n            json.dump(self.habits, f, indent=4)\n\n    def add_habit(self, name, goal):\n        if name not in self.habits:\n            self.habits[name] = {'goal': goal, 'logs': []}\n            self.save_habits()\n            print(f&quot;Added habit: {name} (goal: {goal} times/week)\")\n\n    def log_habit(self, name, completed=True):\n        if name in self.habits:\n            date = datetime.date.today().isoformat()\n            if date not in self.habits[name]['logs']:\n                self.habits[name]['logs'][date] = completed\n                self.save_habits()\n                print(f&quot;Logged {name} for {date}: {completed}\")\n        else:\n            print(f&quot;Habit {name} not found.\")\n\n    def generate_report(self, days=7):\n        end_date = datetime.date.today()\n        start_date = end_date - datetime.timedelta(days=days)\n        report = {}\n        for habit, data in self.habits.items():\n            completed = sum(1 for d in self.date_range(start_date, end_date) if self.is_completed(habit, d))\n            report[habit] = {'completed': completed, 'goal': data['goal'], 'progress': completed / data['goal'] * 100}\n        print(json.dumps(report, indent=4))\n\n    def is_completed(self, habit, date):\n        logs = self.habits[habit]['logs']\n        return logs.get(date.isoformat(), False)\n\n    def date_range(self, start, end):\n        delta = end - start\n        return [start + datetime.timedelta(days=i) for i in range(delta.days + 1)]\n\nif __name__ == '__main__':\n    tracker = HabitTracker()\n    # Example usage\n    tracker.add_habit('Exercise', 5)\n    tracker.log_habit('Exercise')\n    tracker.generate_report()"